/**
 * ESLint rule: test-fixture-parity
 *
 * Warns when a trails `it()` / `test()` whose Rails counterpart uses fixtures
 * lacks a `useFixtures` / `useHandlerTransactionalFixtures` call in the
 * enclosing describe. Mapping: eslint/test-fixture-parity.json (committed,
 * regenerated by `pnpm tsx scripts/generate-fixture-parity-map.ts`).
 */
// fs/path bare per convention; sync fs acceptable — tiny mapping, lint hot path.
import * as fs from "fs";
import * as path from "path";
import { fileURLToPath } from "url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const MAPPING_PATH =
  process.env.TEST_FIXTURE_PARITY_MAP_PATH ??
  path.resolve(__dirname, "test-fixture-parity.json");

// Mtime-based cache: a single lint run reads the file once; tests can swap
// the file on disk between runs and get fresh data (same pattern as expected-fixtures.mjs).
let mappingCache = null;
let mappingCacheMtime = -1;
function loadMapping() {
  if (!fs.existsSync(MAPPING_PATH)) return {};
  const mtime = fs.statSync(MAPPING_PATH).mtimeMs;
  if (mappingCache && mtime === mappingCacheMtime) return mappingCache;
  const raw = JSON.parse(fs.readFileSync(MAPPING_PATH, "utf8"));
  const out = {};
  for (const [k, v] of Object.entries(raw)) out[k] = new Set(v);
  mappingCache = out;
  mappingCacheMtime = mtime;
  return mappingCache;
}

/**
 * Extract the mapping key (trails src-relative path, kebab-case) from the
 * ESLint filename. Returns null for non-activerecord test files.
 *
 * e.g. /repo/packages/activerecord/src/associations/eager.test.ts
 *   → "associations/eager.test.ts"
 */
function trailsRelKey(filename) {
  const norm = filename.replace(/\\/g, "/");
  const m = norm.match(/(?:^|\/)packages\/activerecord\/src\/(.+\.test\.ts)$/);
  return m ? m[1] : null;
}

function normalizeDesc(s) {
  return s.toLowerCase().replace(/\s+/g, " ").trim();
}

/**
 * Walk up parent chain to find the BlockStatement body of the nearest
 * enclosing `describe(...)` call. Returns null if none found.
 */
function enclosingDescribeBody(node) {
  let cur = node.parent;
  while (cur) {
    if (
      cur.type === "CallExpression" &&
      cur.callee?.type === "Identifier" &&
      cur.callee?.name === "describe"
    ) {
      const cb = cur.arguments[cur.arguments.length - 1];
      if (cb && (cb.type === "ArrowFunctionExpression" || cb.type === "FunctionExpression")) {
        if (cb.body?.type === "BlockStatement") return cb.body;
      }
    }
    cur = cur.parent;
  }
  return null;
}

const FIXTURE_CALLEE_NAMES = new Set(["useFixtures", "useHandlerTransactionalFixtures"]);

const rule = {
  meta: {
    type: "suggestion",
    docs: {
      description:
        "Warn when a trails test whose Rails counterpart uses fixtures lacks a `useFixtures` call in its enclosing describe block.",
    },
    schema: [],
    messages: {
      missing:
        'Rails counterpart for "{{desc}}" uses fixtures, but no `useFixtures` / `useHandlerTransactionalFixtures` call was found in the enclosing scope.',
    },
  },
  create(context) {
    const filename = context.filename ?? context.getFilename();
    const key = trailsRelKey(filename);
    if (!key) return {};

    const mapping = loadMapping();
    const fixtureDescs = mapping[key];
    if (!fixtureDescs || fixtureDescs.size === 0) return {};

    // Pass 1: collect describe bodies that contain a useFixtures-family call.
    const describeBodiesWithFixtures = new Set();
    // Pass 1b: collect it()/test() nodes that need checking.
    const toCheck = [];

    return {
      CallExpression(node) {
        const calleeName =
          node.callee?.type === "Identifier" ? node.callee.name : null;
        if (!calleeName) return;

        if (FIXTURE_CALLEE_NAMES.has(calleeName)) {
          const body = enclosingDescribeBody(node);
          describeBodiesWithFixtures.add(body); // null = file scope
          return;
        }

        if (calleeName === "it" || calleeName === "test") {
          const firstArg = node.arguments[0];
          if (firstArg?.type !== "Literal" || typeof firstArg.value !== "string") return;
          const desc = normalizeDesc(firstArg.value);
          if (!fixtureDescs.has(desc)) return;
          const body = enclosingDescribeBody(node);
          toCheck.push({ node: firstArg, desc, body });
        }
      },

      "Program:exit"() {
        // null in the set means useFixtures was called at file scope — it covers
        // all tests in the file regardless of their describe nesting.
        if (describeBodiesWithFixtures.has(null)) return;
        for (const { node, desc, body } of toCheck) {
          if (!describeBodiesWithFixtures.has(body)) {
            context.report({ node, messageId: "missing", data: { desc } });
          }
        }
      },
    };
  },
};

export default rule;
